{"command": "create", "file_text": "from flask import Flask, render_template, request, redirect, url_for, flash
from database import db_session, init_db
from models import URL
import string
import random

app = Flask(__name__)
app.secret_key = 'secret_key_for_session'

@app.teardown_appcontext
def shutdown_session(exception=None):
    db_session.remove()

def generate_short_id(length=6):
    characters = string.ascii_letters + string.digits
    return ''.join(random.choice(characters) for _ in range(length))

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        original_url = request.form.get('url')
        if not original_url:
            flash('URL is required!')
            return redirect(url_for('index'))

        # Check if URL already exists
        url_entry = URL.query.filter_by(original_url=original_url).first()
        if url_entry:
            short_url = request.host_url + url_entry.short_id
            return render_template('index.html', short_url=short_url)

        short_id = generate_short_id()
        # Ensure uniqueness
        while URL.query.filter_by(short_id=short_id).first():
            short_id = generate_short_id()

        new_url = URL(original_url=original_url, short_id=short_id)
        db_session.add(new_url)
        db_session.commit()

        short_url = request.host_url + short_id
        return render_template('index.html', short_url=short_url)

    return render_template('index.html')

@app.route('/<short_id>')
def redirect_to_url(short_id):
    url_entry = URL.query.filter_by(short_id=short_id).first()
    if url_entry:
        return redirect(url_entry.original_url)
    return "URL not found", 404

if __name__ == '__main__':
    init_db()
    app.run(debug=True)
